var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"하아…….","JPN":"はあ……","ENG":"*Sigh...*","TWN":"哈……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"부지런한 이이기에 이른 시각이라도 만날 수 있을 거라 생각했거늘.","JPN":"勤勉な人だから、早朝であっても会えると思ったのに。","ENG":"I thought I might catch him early, knowing how diligent he is.","TWN":"因為是勤奮的人，所以我以為即使是早晨也能見到他。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"역시… 욕심이었나?","JPN":"やはり……欲張りだったかしら。","ENG":"Maybe... I was hoping for too much.","TWN":"果然是貪心嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_07","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"아직 시간은 남아있어.","JPN":"まだ時間はあるわ。","ENG":"There's still time.","TWN":"還有時間。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L13_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"조금 더 기다리면…….","JPN":"もう少し待てば……","ENG":"If I wait just a bit longer...","TWN":"再等一下……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……!!","JPN":"……！！","ENG":"...!!","TWN":"……！！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이런, 오늘은 늦잠이라도 주무신 모양이군요.","JPN":"あら、今日は寝坊でもしたのですか？","ENG":"Oh my, slept in today, did you?","TWN":"哎呀，看來今天你睡過頭了呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"통 오지 않으시길래, 걱정하던 참…… ","JPN":"待っていても来ないので、心配していたところ……","ENG":"You weren't coming, so I was starting to get worri–","TWN":"你一直沒來，我正擔心著……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"응?","JPN":"うん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"당신은…….","JPN":"貴方は……","ENG":"You're...","TWN":"你是……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MAN_PRIDE_NULL_NULL","text":{"KOREA":"이, 인도자님. 도와주세요!","JPN":"み、導き手様。助けてください！","ENG":"S-Star Guide. Please help!","TWN":"引導者大人，請幫幫我！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MAN_PRIDE_NULL_NULL","text":{"KOREA":"알렌이… 알렌이 위험해요!!","JPN":"アレンが……アレンが危ないんです！！","ENG":"It's Allen... He's in danger!!","TWN":"艾倫……艾倫有危險！！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"어, 어떡하지. 이러다 알렌이 잘못되는 거 아니야?","JPN":"ど、どうしよう。アレンに何かあったんじゃないか……","ENG":"W-what do we do?! What if something happens to Allen?","TWN":"啊，怎麼辦？這樣下去艾倫會出事的吧？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"그래도 큰 잘못은 아니잖아. 어쩌면 너그럽게 넘어가실 수도…….","JPN":"でも、悪いことはしてないでしょう？　もしかしたら大目に見てくださるかも……","ENG":"It wasn't even that serious a crime. Maybe she'll show mercy...","TWN":"不過這也不是什麼大錯。或許可以寬容地放過……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"죄질이 아니라 백작님의 일행을 건드렸다는 게 문제야. 제도였으면 최소 감금형이라고!","JPN":"罪の内容よりは伯爵家の一行に手を出したのが問題さ。帝都だったら、禁錮刑は確定のようなもんだって！","ENG":"It's not about the crime. The real issue is he messed with the Count's entourage. If this were the capital, he'd be imprisoned at minimum!","TWN":"問題不在於罪行，而在於觸犯了伯爵大人的隨行人員。如果是在制度內，至少會被判監禁！"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"하아… 하아…….","JPN":"はあ……はあ……","ENG":"*Huff...* *Huff...*","TWN":"哈……哈……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L31_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이게, 대체 무슨……!","JPN":"これは、いったい……！","ENG":"What in the world...?!","TWN":"這到底是怎麼回事……！"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MAID_PRIDE_NULL_A","text":{"KOREA":"아, 인도자님! 마침 잘 오셨어요!","JPN":"み、導き手！　ちょうどいいところに！","ENG":"Oh, Star Guide! Just in time!","TWN":"喔，引導者大人！你來的正好！"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MAID_PRIDE_NULL_A","text":{"KOREA":"이 미천한 것이 뻔뻔하게 구는 탓에, 어찌나 고역이었는지…!!","JPN":"この下賤な者の図々しさに、本当に困っていたのです……！！","ENG":"It's been such a nightmare dealing with this shameless, insolent little thing...!","TWN":"這個卑微的傢伙竟然如此厚顏無恥，真是讓人生氣…！！"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……미천해? 뻔뻔하게 굴어?","JPN":"……下賤？　図々しい？","ENG":"...Insolent? Shameless?","TWN":"……卑微？厚顏無恥？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MAID_PRIDE_NULL_A","text":{"KOREA":"예, 맞아요! 이 평민이 글쎄. 주제도 모르고 제 금반지를 훔쳐갔다고요!","JPN":"はい、そうです！　この平民が、身の程も知らず私の金の指輪を盗んだのです！","ENG":"That's right! This peasant had the audacity to steal my gold ring!","TWN":"是的，沒錯！這個平民居然不知天高地厚，偷走了我的金戒指！"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"부모님의 유품을… 제 시녀들이 억지로 가져갔다는 겁니까?","JPN":"ご両親の遺品を……私の侍女が無理やり奪ったというのですか？","ENG":"A parental heirloom... forcibly taken by my maids?","TWN":"父母的遺物……是我的女傭強行帶走的嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MAN_PRIDE_NULL_NULL","text":{"KOREA":"저, 전부 제 잘못이에요. 알렌의 성격상 가만히 있지 않을 거라는 걸 알았는데.","JPN":"ぜ、全部僕が悪いんです。アレンの性格なら、じっとしてるはずがないってわかってたのに。","ENG":"I-it's all my fault. I should've known Allen wouldn't stay quiet about it.","TWN":"我全都怪我。我知道以艾倫的性格，他不會坐視不管的。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MAN_PRIDE_NULL_NULL","text":{"KOREA":"분한 마음에, 저도 모르게 알렌에게 전부 털어놔서…….","JPN":"悔しくて、ついアレンに全部話しちゃって……","ENG":"I blurted everything out to him in a moment of anger...","TWN":"因為心中不甘，我不由自主地向艾倫傾訴了一切……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"당신, 적당히……!!","JPN":"貴方、いい加減に……！！","ENG":"You've gone too–!!","TWN":"你，說清楚……！！"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L46_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……알렌?","JPN":"……アレン？","ENG":"...Allen?","TWN":"……艾倫？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"죄송합니다. 귀중한 물건에 홀린 나머지 제가 영애분께 폐를 끼쳤군요.","JPN":"申し訳ありません。貴重なものに惑わされ、私がご令嬢にご迷惑をおかけしました。","ENG":"I'm sorry. I let myself be tempted by something precious and caused you trouble, milady.","TWN":"對不起，我被珍貴的物品迷住了，給小姐添麻煩了。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"전부 제 잘못입니다. 어떤 벌이든 달게 받죠.","JPN":"全部私が悪いのです。どんな罰でも受けましょう。","ENG":"It was entirely my doing. I'll accept any punishment you see fit.","TWN":"都是我的錯。無論什麼懲罰，我都願意接受。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MAID_PRIDE_NULL_A","text":{"KOREA":"하. 그럼 내 반지부터 내놔. 처분은 그 이후에 생각해볼 테니까.","JPN":"は。じゃあ、私の指輪から出しなさい。処分はそれから考えるわ。","ENG":"Hah. Then give me back my ring. I'll decide what to do with you after that.","TWN":"那就先把我的戒指拿出來。處罰的事之後再說。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"죄송하지만 그건 힘들겠군요. 반지의 행방에 관해선 저도 아는 것이 없습니다.","JPN":"申し訳ありませんが、それはできません。指輪の行方に関しましては、私もわかりませんので。","ENG":"I'm afraid I can't. I have no idea where it is now.","TWN":"抱歉，那恐怕很難。關於戒指的下落，我也一無所知。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MAID_PRIDE_NULL_A","text":{"KOREA":"이, 이 평민이… 지금 누굴 바보로 알아?!","JPN":"こ、この平民が……私をバカにしているの！？","ENG":"Y-you filthy peasant...! You think I'm stupid?!","TWN":"這，這個平民……你以為我是傻瓜嗎？！"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"죄송합니다. 그에 따른 처분 역시 달게 받겠습니다.","JPN":"申し訳ありません。それについての罰も受けます。","ENG":"I apologize. I'll still accept whatever punishment I deserve.","TWN":"對不起。我會接受處罰。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"MAID_PRIDE_NULL_A","text":{"KOREA":"오냐. 네놈이 그렇다면 원하는 대로 해줘야지.","JPN":"いいわ。じゃあ、お前の望みどおりにしてあげる。","ENG":"Fine. If that's how you want it, so be it.","TWN":"喔，如你所願。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"MAID_PRIDE_NULL_A","text":{"KOREA":"인도자님. 부디, 저놈의 처벌을 제게 맡겨주세요!!","JPN":"導き手。どうか、あいつの処罰を私にお任せください！！","ENG":"Star Guide, please! Let me handle his punishment!!","TWN":"引導者大人，請務必把那傢伙的懲罰交給我！！"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MAID_PRIDE_NULL_A","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"narration","speaker":null,"text":{"KOREA":"백작가에 종신해온 하인켈 가문의 여식은 제 어미와 달리 방자한 품성을 타고났으나.","JPN":"伯爵家で働いてきたハインケル家の娘は、その母とは違い傲慢な性格の所有者であったが。","ENG":"Unlike her mother, the daughter of the long-serving House Heinkel is naturally arrogant.","TWN":"在伯爵家終身服務的海因克家族的女兒，性格與她的母親不同，顯得有些放肆。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"이는 백작가라 한들 그녀의 가문이 보여준 헌신을 가볍게 여길 수 없다는 방증이다.","JPN":"これは伯爵家であっても、彼女の家門が見せてくれた献身を軽んじることができないという証拠である。","ENG":"Still, even the Star Guide can't ignore the loyalty her house has shown.","TWN":"這證明了即使是伯爵家族，也不能輕視她家族所展現的奉獻精神。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"narration","speaker":null,"text":{"KOREA":"사연이 있다 한들, 평민 하나와 복잡하게 얽힌 가문간의 관계에서 선택해야 한다면…….","JPN":"事情があるとはいえ、1人の平民と複雑に絡んだ家同士の関係、どちらかを選べと言われたら……","ENG":"Whatever the backstory, if it's between a commoner and a family entwined with ours...","TWN":"即便有原因，如果要在一個平民和複雜糾葛的家族關係之間做出選擇……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"narration","speaker":null,"text":{"KOREA":"고민할 것도 없이, 답은 명쾌하다.","JPN":"悩むことはない、答えは決まっている。","ENG":"There's no room for hesitation. The answer is obvious.","TWN":"毫不猶豫，答案很明確。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"평민들을 생각한다는 인도자님의 품성은 익히 들어 알고 있습니다.","JPN":"平民のことを思う導き手様の品性は存じております。","ENG":"I've heard of your compassion toward the common folk.","TWN":"我早已聽聞引導者大人關心平民的品性。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"허나 진심으로 저희들을 생각하신다면…….","JPN":"ですが、本当に私たちのことをお思いなら……","ENG":"But if you truly care for us...","TWN":"但是如果你真心為我們著想的話……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그 죄를 뉘우치려는 죄인에게, 부디 <color=#ffd34c>현명한</color> 판단을 내리시길.","JPN":"その罪を悔いている罪人に、どうか<color=#ffd34c>賢明な</color>ご判断を。","ENG":"Then please, make a <color=#ffd34c>wise</color> judgment for a sinner seeking to repent.","TWN":"對於悔過的罪人，請做出<color=#ffd34c>明智的</color>判斷。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"narration","speaker":null,"text":{"KOREA":"그래.","JPN":"そうだ。","ENG":"Very well.","TWN":"沒錯。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"고민할 것도 없이, 답은 명쾌하다.","JPN":"悩むことはない、答えは決まっている。","ENG":"There's no room for hesitation. The answer is obvious.","TWN":"沒什麼好猶豫的，答案很明確。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"의외군요. 공과 사의 구분은 철저한 분이라고 생각했습니다.","JPN":"意外ですね。公私の区別は徹底しているお方だと思っていました。","ENG":"This surprises me. I thought you drew a hard line between duty and emotion.","TWN":"真意外。我以為你是個公私分明的人。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"예. 그랬었죠.","JPN":"ええ。そうでした。","ENG":"I used to.","TWN":"是的，曾經是的。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"잘못의 본질이 시녀분께 있는 이상, 제 편을 들지 않더라도 큰 벌은 없었을 겁니다.","JPN":"非は侍女にある以上、私の肩を持ってくれなかったとしても罰は軽かったはずです。","ENG":"Given the maid's part in this, even if you didn't take my side, I wouldn't have been punished harshly.","TWN":"既然錯誤的本質在於女傭，即使不站在我這邊，也不會受到嚴厲的懲罰。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"알아요. 분명 그랬겠죠.","JPN":"知っています。貴方のいうとおりだったと思います。","ENG":"I know. You're probably right.","TWN":"我知道。肯定是這樣的吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"제법 후련한 표정을 짓고 계시는군요.","JPN":"すっきりしたお顔ですね。","ENG":"You look rather satisfied.","TWN":"你露出了相當輕鬆的表情呢。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……그러게요.","JPN":"……そうですね。","ENG":"...I suppose that's true?","TWN":"……是啊。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"역시, 저도 남들만큼은 이기적인가 봅니다.","JPN":"やはり、私も人並みに自分勝手なところがあるのでしょうね。","ENG":"Perhaps, I'm just as selfish as anyone else.","TWN":"看來我也和別人一樣自私。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"있죠, 알렌.","JPN":"ねえ、アレン。","ENG":"You see, Allen.","TWN":"艾倫。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"말씀하시죠.","JPN":"何でしょうか。","ENG":"Yes?","TWN":"請說吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"만약 제가… 거기서 다른 선택을 내렸다면.","JPN":"もし私が……あそこで違う選択をしていたら。","ENG":"If I had... made a different decision back there.","TWN":"如果我在那時做出了不同的選擇。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"당신은 저를 미워했을까요?","JPN":"貴方は私のことを恨んでいたでしょうか？","ENG":"Would you have hated me?","TWN":"你會討厭我嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그럴 일은 없겠군요.","JPN":"それはありません。","ENG":"No, I don't think I would've.","TWN":"那種事不會發生的吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어째서요?","JPN":"どうして？","ENG":"Why not?","TWN":"為什麼？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"당신은 그럴 자격이 있으신 분이니까요.","JPN":"あなたはその資格があるお方ですから。","ENG":"Because you had the right to.","TWN":"因為你有這樣的資格。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그건, 제가 별의 인도자이기 때문인가요?","JPN":"それは、私が星の導き手だからですか？","ENG":"Because I'm the Star Guide?","TWN":"那是因為我是星之引導者嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"모르겠군요.","JPN":"どうでしょう。","ENG":"I'm not sure.","TWN":"看來你不知道啊。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"제가 알고 지낸 것은 조금 엉뚱해도, 그것을 뒷받침할 정도로 책임감이 강하고.","JPN":"私が知っているのは、少々風変りでも、それを裏付けるほどに責任感が強く。","ENG":"But the person I know, though a bit odd, is incredibly responsible.","TWN":"我認識的你雖然有點古怪，但責任心很強。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"어른스러운 척하지만 여린, 그레이스란 영애 분이시니까요.","JPN":"大人のように振る舞っていても心の弱い、グレースというご令嬢ですから。","ENG":"And underneath all that maturity, the Lady Grace I know is quite delicate.","TWN":"雖然裝作成熟，但畢竟是柔弱的葛瑞絲小姐呢。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……후후. 능숙하시네요.","JPN":"……ふふ。お上手ね。","ENG":"...Haha. You're good at this.","TWN":"……呵呵。你很會說嘛。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L2_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"연습한 보람이 있군요.","JPN":"練習した甲斐がありました。","ENG":"Been practicing.","TWN":"練習是有效果的呢。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"최초의 기억은, 텅 빈 방에 홀로 앉아 환청으로 여겨지는 목소리를 듣는 것.","JPN":"最初の記憶は空っぽの部屋に一人で座り、幻聴と思われる声を聞くこと。","ENG":"My earliest memory was sitting alone in an empty room, listening to a voice that seemed like an auditory hallucination.","TWN":"最初的記憶是，獨自坐在空蕩蕩的房間裡，聽到被認為是幻聽的聲音。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_93"},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"그 후의 기억은, 그저 인도자로서의 소임을 다하기 위해 이상적인 모습을 꾸며내는 것.","JPN":"その後の記憶は、ただ導き手として役目を果たすために理想的な姿を作り出すこと。","ENG":"Everything after that was about crafting the perfect image to fulfill my role as the Star Guide.","TWN":"之後的記憶，只是為了履行引導者的職責而裝扮出理想的樣子。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_94"},{"id":"L6_1","type":"narration","speaker":null,"text":{"KOREA":"누군가의 뜻에 따라 살아온 인생이지만 불만은 없었다.","JPN":"言われるがままに生きてきた人生だが、不満はなかった。","ENG":"I never resented a life lived according to someone else's will.","TWN":"雖然一直按照別人的意願生活，但我並沒有不滿。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_95"},{"id":"L7_1","type":"narration","speaker":null,"text":{"KOREA":"주어진 것에 안주하며 묵묵히 소임을 다하는 것은 내게 어려운 일이 아니었으니까.","JPN":"与えられたものに満足し、黙々と役目を果たすのは私にとって難しいことではなかったから。","ENG":"Fulfilling the role I was given without complaint wasn't difficult for me.","TWN":"安於現狀，默默履行職責對我來說並不困難。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_96"},{"id":"L9_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"있죠, 알렌.","JPN":"ねえ、アレン。","ENG":"You see, Allen.","TWN":"艾倫。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"저는 곧 센트럴 팰리스로 돌아갑니다.","JPN":"私はもうすぐセントラルパレスに帰ります。","ENG":"I'll soon return to the Central Palace.","TWN":"我馬上就要回聖特羅貝里斯了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"예. 알고 있습니다.","JPN":"はい。わかっています。","ENG":"Yes. I know.","TWN":"是。我知道。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"제게 이기적일 자격이 있다면, 조금 욕심을 부려도 괜찮을까요?","JPN":"自分勝手になる資格が私にあるのなら、少し欲を出してみてもいいかしら？","ENG":"If I truly do have the right to be selfish, is it all right if I indulge myself a little?","TWN":"如果我有資格自私一點的話，稍微貪心一點沒關係吧？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"큰 욕심이라 한들 당신이 짊어진 무게만큼은 아니겠죠.","JPN":"あなたの欲が大きかったとしても、背負っているものの重さに比べたら大したことはないでしょう。","ENG":"No matter how selfish it is, it won't weigh as much as what you've carried.","TWN":"再怎麼樣貪心也不及你肩負的重擔吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"그렇다면 사소한 고민일 겁니다.","JPN":"であれば、些細な悩みに過ぎません。","ENG":"So I'd say it's a small concern.","TWN":"那就只是一些小煩惱。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"하지만 나에게 작은 바람이 있다면.","JPN":"でも、私に小さい願いがあるとしたら。","ENG":"But if I have one small wish...","TWN":"不過，如果我有一個小小的願望的話。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_97"},{"id":"L16_1","type":"narration","speaker":null,"text":{"KOREA":"그 마음은 분명, 당신으로부터 비롯되었다.","JPN":"その心はきっと、貴方から始まった。","ENG":"That feeling, without a doubt, came from you.","TWN":"那份心意，毫無疑問是源自於你。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"}}},"voice":"AB_UI_UNIT_VOICE_OPR_GRACE_IN_TRAILER_98"},{"id":"L18_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……알렌.","JPN":"……アレン。","ENG":"...Allen.","TWN":"……艾倫。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"저는 당신이 필요합니다.","JPN":"私は貴方が必要です。","ENG":"I need you.","TWN":"我需要你。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"……물건이나 훔칠 줄 아는 양치기가 백작령에 도움이 될 지는 모르겠군요.","JPN":"……盗みくらいしかできない羊飼いが伯爵領のお役に立てるでしょうか。","ENG":"...I'm not sure what good a shepherd who only knows how to steal things could do for the County.","TWN":"……一個隻會偷東西的牧羊人能否對伯爵領地有所幫助，我還真不確定呢。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"사욕을 부린 호위가 타인으로부터 빼앗은 물건이었지요.","JPN":"護衛が私利私欲を満たすために、他人から奪い取った物でしたね。","ENG":"It was one of my guards who stole, driven by greed.","TWN":"貪婪的護衛從他人那裡奪來的東西吧。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"당신이 아니었다면, 재물에 취한 사람이 제 곁에 머물렀을 거고요.","JPN":"貴方がいなかったら、その貪欲な人間は今も私の側にいたはずです。","ENG":"If it weren't for you, I might've kept someone like that at my side.","TWN":"如果不是你，貪圖財物的人就會留在我身邊了。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"하지만 전 평민에 불과합니다.","JPN":"ですが私は平民です。","ENG":"But I am just a commoner.","TWN":"但是我只是個平民而已。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"신분의 귀천은 중요하지 않습니다.","JPN":"身分が重要なのではありません。","ENG":"Status means nothing.","TWN":"身份的高低並不重要。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"진정 중요한 건… 그래요.","JPN":"本当に重要なのは……そう。","ENG":"What truly matters is... yes.","TWN":"真正重要的是……。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"어두운 밤에 길 잃고 헤매는 이들을 구원해줄, 그 내면의 찬란한 별빛이지요.","JPN":"闇夜で道に迷っている者たちを救う、その胸の内に輝く星の光です。","ENG":"The radiant starlight inside you, the kind that saves those lost in the night.","TWN":"在黑夜中拯救迷失徘徊之人的，是內心那璀璨的星光。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"제 평범함은 당신께 누가 될 겁니다.","JPN":"私の平凡さはあなたの迷惑となります。","ENG":"My ordinariness would only weigh you down.","TWN":"我的平凡會成為你的負擔。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"평범하지만, 제게 있어선 특별했습니다.","JPN":"平凡ですが、私にとっては特別でした。","ENG":"You may be ordinary, but to me, you were special.","TWN":"雖然平凡，但對我來說卻是特別的。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그것만으로는 부족할까요?","JPN":"それだけでは足りませんか？","ENG":"Isn't that enough?","TWN":"光是這樣還不夠嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"이제 와서 고백하자면 저는 욕심쟁이입니다.","JPN":"実を言うと、私は欲張りなのです。","ENG":"I'll admit it now. I'm greedy.","TWN":"現在坦白說，我是個貪心鬼。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"그러니… 한 번 더 말할게요.","JPN":"だから……もう一度言います。","ENG":"So... let me say this again.","TWN":"所以……我再說一次。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"……알렌.","JPN":"……アレン。","ENG":"...Allen.","TWN":"……艾倫。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"GRACE_ORDER_NULL_NULL","text":{"KOREA":"저를 지켜주시겠어요?","JPN":"私を守ってくれませんか？","ENG":"Will you stay by my side?","TWN":"你會保護我嗎？"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GRACE_ORDER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"예.","JPN":"はい。","ENG":"As you wish.","TWN":"是的。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ALLEN_SCHOOL_NPC_NULL","text":{"KOREA":"제 모든 것을 걸고서, 반드시.","JPN":"私のすべてをかけて、必ず。","ENG":"With everything I have, I will.","TWN":"我將傾盡所有，務必做到。"},"stage":{"bg":"SKY_SUNSET","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};